const results = [];
const seenUrls = new Set();
for (const item of $input.all()) {
  const json = item.json;
  let normalized = null;

  if (json.rss?.channel?.item) {
     const items = Array.isArray(json.rss.channel.item) ? json.rss.channel.item : [json.rss.channel.item];
     items.forEach(i => results.push({ json: { url: i.link, titol: i.title, font: 'E-tauler Anuncis', tipus: 'edicte', esOficial: true, data_publicacio: i.pubDate } }));
  } else if (json.data_publicacio && json.nom_organ_contractacio) {
     results.push({ json: { url: json.enllac_al_perfil_del_contractant || json.url || 'http', titol: json.objecte_del_contracte, font: 'Perfil Contractant', tipus: 'licitació', esOficial: true, data_publicacio: json.data_publicacio, import_detectat: json.valor_estimat_del_contracte, tipus_tramit: json.tipus_tramit } });
  } else if (json.url?.includes('.pdf')) {
     results.push({ json: { url: json.url, titol: json.url.split('/').pop(), font: 'Acords Junta Govern', tipus: 'PDF', esOficial: true } });
  }
}

const dedup = results.filter(i => {
  if (!i.json.url) return false;
  if (seenUrls.has(i.json.url)) return false;
  seenUrls.add(i.json.url);
  return true;
});
return dedup;

const existing = new Set($input.all()[0].json.map(r => r.url_original));
try {
  let candidates = $('Normalitza i Filtra').all();
  let news = candidates.filter(i => !existing.has(i.json.url));
  news.sort((a,b) => (a.json.tipus === 'PDF' ? -1 : 1));
  return news.slice(0, 15);
} catch (e) { return []; }

const html = $json.data || $json.body || '';
let txt = html.replace(/<script[\s\S]*?<\/script>/gi, ' ').replace(/<style[\s\S]*?<\/style>/gi, ' ').replace(/<[^>]+>/g, ' ').replace(/\s{2,}/g, ' ').trim();
const loopJson = $('Filtra Nous').item.json;
return { json: { ...loopJson, contingut_complet: txt.slice(0, 6000), confianca: txt.length < 50 ? 'BAIXA' : 'ALTA' } };

const ia = $json.message?.content || '';
const original = $('Extreu Text').item.json;
let res = {};
['URGENCIA', 'RESUM', 'VENCIMENT', 'IMPORT', 'TEMA', 'TIPUS_TRAM', 'CONFIANCA', 'PER A L\'OPOSICIO', 'PROPOSTA ACCIO', 'PREGUNTA PLE', 'EXPEDIENT'].forEach(k => {
  const m = ia.match(new RegExp('^' + k.replace(/[.*+?^${}()|[\]\\]/g, '\\$&') + ':\\s*(.*)$', 'm'));
  res[k.toLowerCase().replace(/[^a-z0-9]/g, '_')] = m ? m[1].trim() : '';
});

let urg = res.urgencia || 'INFORMATIU';
const amt = parseFloat(res.import?.replace(/[^0-9.]/g,''));
const days = res.venciment ? (new Date(res.venciment.split('/').reverse().join('-')) - new Date())/86400000 : 999;
if (days > 0 && days < 15) urg = 'URGENT';
if (!isNaN(amt) && amt > 50000 && urg !== 'URGENT') urg = 'IMPORTANT';
if (original.font.includes('Contractant') && urg === 'INFORMATIU') urg = 'IMPORTANT';
if (original.tipus === 'PDF' && original.font.includes('Acords') && urg === 'INFORMATIU') urg = 'IMPORTANT';

return { json: { ...original, ...res, final_urgencia: urg, num_import: isNaN(amt) ? null : amt, sql_venciment: days < 999 ? res.venciment.split('/').reverse().join('-') : null } };

const all = $('Aplica Regles Urgencia').all().map(i => i.json);
const num = all.length;
const urgs = all.filter(i => i.final_urgencia === 'URGENT');
let tg = '*Resum diari*\n\n';
all.forEach(a => tg += `- ${a.titol}\n`);
return { json: { hiHaNovetats: num > 0, hiHaUrgents: urgs.length > 0, missatge: tg, htmlBody: '<b>Resum html</b>', urgents: urgs, emailSubject: 'Resum ' + num } };
